bash_commands.command:
cat > /tmp/analyze_distutils.py << 'EOF'
import json
import subprocess

# Get all references with line numbers
result = subprocess.run(
    ['grep', '-rn', '--include=*.py', 'numpy\\.distutils\\|from numpy import distutils\\|from numpy.distutils\\|numpy/distutils\\|numpy/f2py/_backends/_distutils', 'numpy', 'scipy'],
    capture_output=True,
    text=True
)

# Parse results
files_data = {}
for line in result.stdout.strip().split('\n'):
    if not line:
        continue
    parts = line.split(':')
    if len(parts) >= 3:
        filepath = parts[0]
        lineno = parts[1]
        content = ':'.join(parts[2:]).strip()

        if filepath not in files_data:
            files_data[filepath] = []
        files_data[filepath].append({
            'line': int(lineno),
            'content': content
        })

# Print results
for filepath in sorted(files_data.keys()):
    refs = files_data[filepath]
    print(f"\n{filepath}:")
    for ref in sorted(refs, key=lambda x: x['line']):
        print(f"  Line {ref['line']}: {ref['content'][:100]}")
EOF
